    $e=strtolower(pathinfo($f,PATHINFO_EXTENSION));
    $m=['jpg'=>'🖼️','jpeg'=>'🖼️','png'=>'🖼️','gif'=>'🖼️','webp'=>'🖼️','svg'=>'🖼️','bmp'=>'🖼️',
