// ─── Self-unregistering Service Worker (kills any stale SW from past) ──
if ($action === 'sw' || preg_match('#/sw\.js(\?|$)#', $_SERVER['REQUEST_URI'] ?? '')) {
    header('Content-Type: application/javascript; charset=utf-8');
    header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
    header('Pragma: no-cache');
    echo "self.addEventListener('install', e => self.skipWaiting());\n";
    echo "self.addEventListener('activate', e => {\n";
    echo "  e.waitUntil(self.registration.unregister().then(() =>\n";
    echo "    self.clients.matchAll().then(cs => cs.forEach(c => c.navigate(c.url)))\n";
    echo "  ));\n";
    echo "});\n";
    exit;
}

// ─── Render captcha as PNG image (anti-bot) ──────────────────
if ($action === 'captcha_image') {
    if (!extension_loaded('gd')) {
        header('Content-Type: image/png');
        echo base64_decode('iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
        exit;
    }
    if (empty($_SESSION['math_captcha'])) {
        math_captcha_generate();
    }
    $q = $_SESSION['math_captcha']['question'] ?? '? + ? = ?';

    header('Content-Type: image/png');
    header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
    header('Pragma: no-cache');

    $w = 160; $h = 50;
    $im = imagecreatetruecolor($w, $h);
    $bg    = imagecolorallocate($im, 10, 14, 26);
    $fg    = imagecolorallocate($im, 253, 230, 104);
    $noise = imagecolorallocate($im, 71, 85, 105);
    imagefilledrectangle($im, 0, 0, $w, $h, $bg);

    for ($i = 0; $i < 6; $i++) {
        imageline($im, random_int(0,$w), random_int(0,$h), random_int(0,$w), random_int(0,$h), $noise);
    }
    for ($i = 0; $i < 80; $i++) {
        imagesetpixel($im, random_int(0,$w-1), random_int(0,$h-1), $noise);
    }

    $chars = str_split($q);
    $x = 12;
    $fontSize = 5;
    foreach ($chars as $c) {
        $y = 16 + random_int(-3, 3);
        imagestring($im, $fontSize, $x, $y, $c, $fg);
        $x += 13 + random_int(-2, 2);
    }

    imagepng($im);
    imagedestroy($im);
    exit;
}

