// ── passkey_list ────────────────────────────────────────────────
if($action==='passkey_list'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])){echo json_encode(['items'=>[]]);exit;}
    $st=$pdo->prepare("SELECT id,device_name,created_at FROM passkeys WHERE username=? ORDER BY created_at DESC");
    $st->execute([$_SESSION['user']]);
    $items=[];
    foreach($st->fetchAll() as $row){
        $items[]=['id'=>(int)$row['id'],'name'=>htmlspecialchars($row['device_name']),'created'=>to_jalali($row['created_at'])];
    }
    echo json_encode(['items'=>$items]);exit;
}

// ── passkey_register_challenge ──────────────────────────────────
if($action==='passkey_register_challenge'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])){echo json_encode(['error'=>'not_logged_in']);exit;}
    $ch=random_bytes(32);
    $_SESSION['pk_reg_ch']=pk_b64e($ch); // store as base64 to avoid session binary corruption
    $stu=$pdo->prepare("SELECT id FROM users WHERE username=?");$stu->execute([$_SESSION['user']]);
    $uid=(int)$stu->fetchColumn();
    $ex=[];
    $sx=$pdo->prepare("SELECT credential_id FROM passkeys WHERE username=?");$sx->execute([$_SESSION['user']]);
    foreach($sx->fetchAll() as $r)$ex[]=['id'=>$r['credential_id'],'type'=>'public-key','transports'=>['internal']];
    echo json_encode([
        'challenge'  =>pk_b64e($ch),
        'rp'         =>['id'=>pk_rpid(),'name'=>'XCloud'],
        'user'       =>['id'=>pk_b64e(pack('N',$uid)),'name'=>$_SESSION['user'],'displayName'=>$_SESSION['user']],
        'pubKeyCredParams'=>[['type'=>'public-key','alg'=>-7],['type'=>'public-key','alg'=>-257]],
        'timeout'    =>60000,
        'excludeCredentials'=>$ex,
        'authenticatorSelection'=>['authenticatorAttachment'=>'platform','residentKey'=>'required','requireResidentKey'=>true,'userVerification'=>'required'],
        'hints'      =>['client-device'],
        'attestation'=>'none',
    ]);exit;
}

// ── passkey_register_verify ─────────────────────────────────────
if($action==='passkey_register_verify'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])||empty($_SESSION['pk_reg_ch'])){echo json_encode(['ok'=>false,'error'=>'session expired']);exit;}
    $body=json_decode(file_get_contents('php://input'),true);
    if(!$body){echo json_encode(['ok'=>false,'error'=>'invalid body']);exit;}
    try{
        $cdJson=pk_b64d($body['clientDataJSON']??'');
        $cd=json_decode($cdJson,true);
        if(($cd['type']??'')!=='webauthn.create')throw new Exception('wrong type');
        if(!hash_equals(pk_b64d($_SESSION['pk_reg_ch']),pk_b64d($cd['challenge']??'')))throw new Exception('challenge mismatch');
        if(($cd['origin']??'')!==pk_origin())throw new Exception('origin mismatch');
        unset($_SESSION['pk_reg_ch']);
        $off=0;$attBytes=pk_b64d($body['attestationObject']??'');
        $att=cbor_read($attBytes,$off);
        $authData=$att['authData']??'';
        $parsed=pk_parse_authdata($authData);
        if(!$parsed||!$parsed['up'])throw new Exception('user presence not set');
        if(empty($parsed['pubKeyPem']))throw new Exception('no public key');
        if(!hash_equals(hash('sha256',pk_rpid(),true),$parsed['rpIdHash']))throw new Exception('rpId mismatch');
        $credId=pk_b64e($parsed['credId']);
        $name=substr(trim($body['name']??'Passkey'),0,80)?:'Passkey';
        $stu=$pdo->prepare("SELECT id FROM users WHERE username=?");$stu->execute([$_SESSION['user']]);
        $uid=(int)$stu->fetchColumn();
        $ins=$pdo->prepare("INSERT INTO passkeys (user_id,username,credential_id,public_key,sign_count,device_name) VALUES(?,?,?,?,?,?)");
        $ins->execute([$uid,$_SESSION['user'],$credId,$parsed['pubKeyPem'],$parsed['signCount'],htmlspecialchars($name)]);
        logActivity($pdo,$_SESSION['user'],'passkey_register',null,"Passkey ثبت شد: $name");
        echo json_encode(['ok'=>true]);
    }catch(Exception $e){echo json_encode(['ok'=>false,'error'=>$e->getMessage()]);}
    exit;
}

// ── passkey_auth_challenge ──────────────────────────────────────
if($action==='passkey_auth_challenge'){
    header('Content-Type: application/json');
    $ch=random_bytes(32);
    $_SESSION['pk_auth_ch']=pk_b64e($ch); // store as base64 to avoid session binary corruption
    $_SESSION['pk_auth_ts']=time();
    $allow=[];
    $uname=trim($_GET['u']??'');
    if($uname){
        $sx=$pdo->prepare("SELECT credential_id FROM passkeys WHERE username=?");$sx->execute([$uname]);
        foreach($sx->fetchAll() as $r)$allow[]=['id'=>$r['credential_id'],'type'=>'public-key','transports'=>['internal']];
    }
    echo json_encode(['challenge'=>pk_b64e($ch),'timeout'=>60000,'rpId'=>pk_rpid(),'allowCredentials'=>$allow,'userVerification'=>'required','hints'=>['client-device']]);
    exit;
}

// ── passkey_auth_verify ─────────────────────────────────────────
if($action==='passkey_auth_verify'){
    header('Content-Type: application/json');
    if(empty($_SESSION['pk_auth_ch'])||(time()-($_SESSION['pk_auth_ts']??0))>120){
        echo json_encode(['ok'=>false,'error'=>'challenge expired']);exit;
    }
    $body=json_decode(file_get_contents('php://input'),true);
    if(!$body){echo json_encode(['ok'=>false,'error'=>'invalid body']);exit;}
    try{
        $cdJson=pk_b64d($body['clientDataJSON']??'');
        $cd=json_decode($cdJson,true);
        if(($cd['type']??'')!=='webauthn.get')throw new Exception('wrong type');
        if(!hash_equals(pk_b64d($_SESSION['pk_auth_ch']),pk_b64d($cd['challenge']??'')))throw new Exception('challenge mismatch');
        if(($cd['origin']??'')!==pk_origin())throw new Exception('origin mismatch');
        unset($_SESSION['pk_auth_ch'],$_SESSION['pk_auth_ts']);
        $st=$pdo->prepare("SELECT * FROM passkeys WHERE credential_id=?");$st->execute([$body['id']??'']);
        $cred=$st->fetch();
        if(!$cred)throw new Exception('credential not found');
        $authData=pk_b64d($body['authenticatorData']??'');
        $sig=pk_b64d($body['signature']??'');
        if(!hash_equals(hash('sha256',pk_rpid(),true),substr($authData,0,32)))throw new Exception('rpId mismatch');
        if(!(ord($authData[32])&0x01))throw new Exception('user presence not set');
        if(!pk_verify($cred['public_key'],$authData,$cdJson,$sig))throw new Exception('signature invalid');
        $newCnt=unpack('N',substr($authData,33,4))[1];
        if((int)$cred['sign_count']>0&&$newCnt<=(int)$cred['sign_count'])throw new Exception('sign count regression');
        $pdo->prepare("UPDATE passkeys SET sign_count=? WHERE id=?")->execute([$newCnt,$cred['id']]);
        $stu=$pdo->prepare("SELECT username,role FROM users WHERE id=?");$stu->execute([$cred['user_id']]);
        $u=$stu->fetch();
        if(!$u)throw new Exception('user not found');
        session_regenerate_id(true);
        $_SESSION['user']=$u['username'];$_SESSION['role']=$u['role'];
        logActivity($pdo,$u['username'],'login',null,'ورود با Passkey');
        echo json_encode(['ok'=>true,'redirect'=>'?action=dashboard']);
    }catch(Exception $e){
        logActivity($pdo,'unknown','login_failed',null,'Passkey: '.$e->getMessage());
        echo json_encode(['ok'=>false,'error'=>$e->getMessage()]);
    }
    exit;
}

// ── passkey_delete ──────────────────────────────────────────────
if($action==='passkey_delete'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])){echo json_encode(['ok'=>false]);exit;}
    $pid=(int)($_POST['id']??0);
    $pdo->prepare("DELETE FROM passkeys WHERE id=? AND username=?")->execute([$pid,$_SESSION['user']]);
    logActivity($pdo,$_SESSION['user'],'passkey_delete');
    echo json_encode(['ok'=>true]);
    exit;
}

if ($action == 'login_process') {
    verifyCsrf();
    $identifier = trim($_POST['username'] ?? '');
    $p = $_POST['password'] ?? '';

    if ($identifier === '' || $p === '') {
        header("Location: index.php?error=1"); exit;
    }

    // Lookup by username OR email (case-insensitive for email)
    $st = $pdo->prepare("SELECT username, password, role FROM users
        WHERE username = ? OR email = LOWER(?) LIMIT 1");
    $st->execute([$identifier, $identifier]);
    $ud = $st->fetch();

    if ($ud && password_verify($p, $ud['password'])) {
        session_regenerate_id(true);
        $_SESSION['user'] = $ud['username'];
        $_SESSION['role'] = $ud['role'];
        logActivity($pdo, $ud['username'], 'login', null, 'ورود موفق');
        header("Location: ?action=dashboard"); exit;
    }

    logActivity($pdo, $identifier ?: 'unknown', 'login_failed', null, 'تلاش ناموفق');
    header("Location: index.php?error=1"); exit;
}

if($action=='logout'){if(isset($_SESSION['user']))logActivity($pdo,$_SESSION['user'],'logout');session_destroy();header("Location: index.php");exit;}

if($action=='upload_process'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $up=getUserUploadPath($_SESSION['user']);
    $files=normalizeFilesArray($_FILES["fileToUpload"]??null);
    if(empty($files)){header("Location: ?action=dashboard&msg=upload_error");exit;}
    $ok=0;$fail=0;$tooLarge=0;$quota=0;
    $usedBytes=getDirSize($up);
    foreach($files as $f){
        if($f["error"]!==UPLOAD_ERR_OK){$fail++;continue;}
        if($f["size"]>$MAX_FILE_SIZE){$tooLarge++;$fail++;continue;}
        if(($usedBytes+$f["size"])>$MAX_STORAGE_PER_USER){$quota++;$fail++;continue;}
        $on=basename($f["name"]);$ext=strtolower(pathinfo($on,PATHINFO_EXTENSION));
        $tf=$up.$on;$c=1;$nwe=pathinfo($on,PATHINFO_FILENAME);
        while(file_exists($tf)){$tf=$up.$nwe.'_'.$c.'.'.$ext;$c++;}
        if(move_uploaded_file($f["tmp_name"],$tf)){
            logActivity($pdo,$_SESSION['user'],'upload',basename($tf),"حجم: ".formatBytes($f["size"])." | نوع: $ext");
            $usedBytes+=$f["size"];$ok++;
        }else{$fail++;}
    }
    header("Location: ?action=dashboard&".buildUploadStatusQuery($ok,$fail,$tooLarge,$quota));exit;
}

