// ── Public file upload (admin only) ──
if($action=='public_upload_process'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    global $public_base;
    $files=normalizeFilesArray($_FILES["fileToUpload"]??null);
    if(empty($files)){header("Location: ?action=dashboard&tab=public&msg=upload_error");exit;}
    $selectedUsers=$_POST['access_users']??[];
    if(!is_array($selectedUsers))$selectedUsers=[];
    $ok=0;$fail=0;$tooLarge=0;
    foreach($files as $f){
        if($f["error"]!==UPLOAD_ERR_OK){$fail++;continue;}
        if($f["size"]>$MAX_FILE_SIZE){$tooLarge++;$fail++;continue;}
        $on=basename($f["name"]);$ext=strtolower(pathinfo($on,PATHINFO_EXTENSION));
        $tf=$public_base.$on;$c=1;$nwe=pathinfo($on,PATHINFO_FILENAME);
        while(file_exists($tf)){$tf=$public_base.$nwe.'_'.$c.'.'.$ext;$c++;}
        $finalName=basename($tf);
        if(move_uploaded_file($f["tmp_name"],$tf)){
            $st=$pdo->prepare("INSERT INTO public_files (filename,uploaded_by,file_size) VALUES(?,?,?)");
            $st->execute([$finalName,$_SESSION['user'],$f["size"]]);
            $fileId=$pdo->lastInsertId();
            foreach($selectedUsers as $su){
                $su=trim($su);if(empty($su))continue;
                $ins=$pdo->prepare("INSERT IGNORE INTO public_file_access (file_id,username) VALUES(?,?)");
                $ins->execute([$fileId,$su]);
            }
            logActivity($pdo,$_SESSION['user'],'public_upload',$finalName,"حجم: ".formatBytes($f["size"]));
            $ok++;
        }else{$fail++;}
    }
    header("Location: ?action=dashboard&tab=public&".buildUploadStatusQuery($ok,$fail,$tooLarge,0));exit;
}

// ── Update public file access ──
if($action=='update_public_access'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $fileId=(int)($_POST['file_id']??0);
    if($fileId>0){
        $pdo->prepare("DELETE FROM public_file_access WHERE file_id=?")->execute([$fileId]);
        $selectedUsers=$_POST['access_users']??[];
        if(is_array($selectedUsers)){
            foreach($selectedUsers as $su){
                $su=trim($su);if(empty($su))continue;
                $ins=$pdo->prepare("INSERT IGNORE INTO public_file_access (file_id,username) VALUES(?,?)");
                $ins->execute([$fileId,$su]);
            }
        }
        logActivity($pdo,$_SESSION['user'],'update_public_access',"file_id=$fileId");
    }
    header("Location: ?action=dashboard&tab=public&msg=access_updated");exit;
}

// ── Delete public file (admin only) ──
if($action=='delete_public_file'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");
    global $public_base;
    $fid=(int)($_GET['file_id']??0);
    $st=$pdo->prepare("SELECT * FROM public_files WHERE id=?");$st->execute([$fid]);$pf=$st->fetch();
    if($pf){
        $fp=$public_base.$pf['filename'];
        if(file_exists($fp))@unlink($fp);
        $pdo->prepare("DELETE FROM public_file_access WHERE file_id=?")->execute([$fid]);
        $pdo->prepare("DELETE FROM public_files WHERE id=?")->execute([$fid]);
        logActivity($pdo,$_SESSION['user'],'delete_public',$pf['filename']);
    }
    header("Location: ?action=dashboard&tab=public&msg=deleted");exit;
}

// ── Share file (admin or user with can_share) ──
if($action=='share_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $ps=$pdo->prepare("SELECT role,can_share FROM users WHERE username=?");$ps->execute([$_SESSION['user']]);$pr=$ps->fetch();
    $isAdmin=$pr&&$pr['role']==='admin';$canShare=$isAdmin||($pr&&$pr['can_share']);
    if(!$canShare){header("Location: ?action=dashboard&msg=no_permission");exit;}
    $fn=basename($_POST['filename']??'');$owner=$_POST['owner']??'';$targets=$_POST['share_with']??[];
    if(!empty($fn)&&!empty($owner)&&is_array($targets)){
        $fp=getUserUploadPath($owner).$fn;
        if(file_exists($fp)){
            foreach($targets as $tgt){
                $tgt=trim($tgt);if(empty($tgt)||$tgt===$owner)continue;
                $ins=$pdo->prepare("INSERT IGNORE INTO file_shares (original_owner,filename,shared_with,shared_by) VALUES(?,?,?,?)");
                $ins->execute([$owner,$fn,$tgt,$_SESSION['user']]);
            }
            logActivity($pdo,$_SESSION['user'],'share_file',$fn,"صاحب: $owner | با: ".implode(',',$targets));
        }
    }
    $redirect="?action=dashboard&msg=shared";
    if($owner!==$_SESSION['user'])$redirect.="&view_user=".urlencode($owner);
    header("Location: $redirect");exit;
}

// ── Unshare/remove shared file from recipient's view ──
if($action=='unshare_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $sid=(int)($_GET['share_id']??0);
    $st=$pdo->prepare("SELECT * FROM file_shares WHERE id=?");$st->execute([$sid]);$sh=$st->fetch();
    if($sh){
        // recipient can remove from their own view, or admin can remove
        if($sh['shared_with']===$_SESSION['user']||$_SESSION['role']==='admin'){
            $pdo->prepare("DELETE FROM file_shares WHERE id=?")->execute([$sid]);
            logActivity($pdo,$_SESSION['user'],'unshare_file',$sh['filename'],"از: ".$sh['shared_with']);
        }
    }
    header("Location: ?action=dashboard&msg=unshared");exit;
}

// ── Remove self from public file access ──
if($action=='remove_public_access'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fid=(int)($_GET['file_id']??0);
    $pdo->prepare("DELETE FROM public_file_access WHERE file_id=? AND username=?")->execute([$fid,$_SESSION['user']]);
    header("Location: ?action=dashboard&tab=public&msg=removed");exit;
}

// ── Get shares for a file (AJAX) ──
if($action=='get_shares'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])){echo json_encode(['shares'=>[]]);exit;}
    $fn=basename($_GET['filename']??'');$owner=$_GET['owner']??'';
    $st=$pdo->prepare("SELECT id,shared_with,shared_by,created_at FROM file_shares WHERE original_owner=? AND filename=?");
    $st->execute([$owner,$fn]);
    echo json_encode(['shares'=>$st->fetchAll(PDO::FETCH_ASSOC)]);exit;
}

// ── Get public file access list (AJAX) ──
if($action=='get_public_access'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin'){echo json_encode(['users'=>[]]);exit;}
    $fid=(int)($_GET['file_id']??0);
    $st=$pdo->prepare("SELECT username FROM public_file_access WHERE file_id=?");$st->execute([$fid]);
    echo json_encode(['users'=>$st->fetchAll(PDO::FETCH_COLUMN)]);exit;
}

if($action=='download'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fn=basename($_GET['name']??'');$owner=$_GET['owner']??$_SESSION['user'];
    $isPublicDl=isset($_GET['public_file_id']);
    $ps=$pdo->prepare("SELECT can_download,role FROM users WHERE username=?");$ps->execute([$_SESSION['user']]);$pr=$ps->fetch();
    if(!$pr||($pr['role']!=='admin'&&!$pr['can_download'])){header("Location: ?action=dashboard&msg=no_permission");exit;}

    if($isPublicDl){
        // Public file download
        $pfid=(int)$_GET['public_file_id'];
        $pfs=$pdo->prepare("SELECT * FROM public_files WHERE id=?");$pfs->execute([$pfid]);$pf=$pfs->fetch();
        if($pf){
            $hasAccess=$_SESSION['role']==='admin';
            if(!$hasAccess){$ac=$pdo->prepare("SELECT id FROM public_file_access WHERE file_id=? AND username=?");$ac->execute([$pfid,$_SESSION['user']]);$hasAccess=(bool)$ac->fetch();}
            if($hasAccess){
                $fp=$public_base.$pf['filename'];
                if(file_exists($fp)){
                    logActivity($pdo,$_SESSION['user'],'download',$pf['filename'],'فایل عمومی');
                    header('Content-Type: application/octet-stream');header('Content-Disposition: attachment; filename="'.$pf['filename'].'"');
                    header('Content-Length: '.filesize($fp));readfile($fp);exit;
                }
            }
        }
        header("Location: ?action=dashboard&tab=public&msg=not_found");exit;
    }

    // Check access: owner, admin, or shared with user
    $hasAccess=($_SESSION['role']==='admin'||$owner===$_SESSION['user']);
    if(!$hasAccess){
        $sc=$pdo->prepare("SELECT id FROM file_shares WHERE original_owner=? AND filename=? AND shared_with=?");
        $sc->execute([$owner,$fn,$_SESSION['user']]);$hasAccess=(bool)$sc->fetch();
    }
    if(!$hasAccess)die("دسترسی غیرمجاز!");

    $fp=getUserUploadPath($owner).$fn;
    if(file_exists($fp)&&is_file($fp)){
        logActivity($pdo,$_SESSION['user'],'download',$fn,"از: $owner");
        header('Content-Type: application/octet-stream');header('Content-Disposition: attachment; filename="'.$fn.'"');
        header('Content-Length: '.filesize($fp));readfile($fp);exit;
    }
    header("Location: ?action=dashboard&msg=not_found");exit;
}

if($action=='delete_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fn=basename($_GET['name']??'');$owner=$_GET['owner']??$_SESSION['user'];
    if($_SESSION['role']!=='admin'){
        if($owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
        $dc=$pdo->prepare("SELECT can_delete FROM users WHERE username=?");$dc->execute([$_SESSION['user']]);$dr=$dc->fetch();
        if(!$dr||!$dr['can_delete']){header("Location: ?action=dashboard&msg=no_permission");exit;}
    }
    $fp=getUserUploadPath($owner).$fn;
    if(file_exists($fp)&&is_file($fp)){
        $fsize=filesize($fp);
        $trashFn=time().'_'.preg_replace('/[^a-zA-Z0-9_-]/','_',$owner).'_'.$fn;
        $tp=$trash_base.$trashFn;
        if(rename($fp,$tp)){
            $st=$pdo->prepare("INSERT INTO trash_items (original_owner,original_filename,trash_filename,deleted_by,file_size) VALUES(?,?,?,?,?)");
            $st->execute([$owner,$fn,$trashFn,$_SESSION['user'],$fsize]);
            logActivity($pdo,$_SESSION['user'],'delete',$fn,"از: $owner | به سطل زباله منتقل شد");
            header("Location: ?action=dashboard&msg=deleted".($owner!==$_SESSION['user']?"&view_user=$owner":""));exit;
        }
    }
    header("Location: ?action=dashboard&msg=not_found");exit;
}

if($action=='rename_file'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $on=basename($_POST['old_name']??'');$nn=basename($_POST['new_name']??'');$owner=$_POST['owner']??$_SESSION['user'];
    if(!empty($on)&&!empty($nn)){
        $op=getUserUploadPath($owner).$on;$np=getUserUploadPath($owner).$nn;
        if(file_exists($op)&&!file_exists($np)){rename($op,$np);logActivity($pdo,$_SESSION['user'],'rename',"$on → $nn","پوشه: $owner");
            header("Location: ?action=dashboard&msg=renamed".($owner!==$_SESSION['user']?"&view_user=$owner":""));exit;}
    }
    header("Location: ?action=dashboard&msg=rename_error");exit;
}

if($action=='file_info'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fn=basename($_GET['name']??'');$owner=$_GET['owner']??$_SESSION['user'];
    if($_SESSION['role']!=='admin'&&$owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
    $fp=getUserUploadPath($owner).$fn;
    if(!file_exists($fp)||!is_file($fp)){header("Location: ?action=dashboard&msg=not_found");exit;}
    $csrf=generateCsrfToken();
