        'ext'=>strtolower(pathinfo($fn,PATHINFO_EXTENSION)),'modified'=>to_jalali(date("Y-m-d H:i:s",filemtime($fp))),
        'modified_raw'=>date("Y-m-d H:i:s",filemtime($fp)),'owner'=>$owner,
        'permissions'=>decoct(fileperms($fp)&0777),'dimensions'=>getImageDimensions($fp),'md5'=>md5_file($fp)];
    ?><!DOCTYPE html><html lang="fa" dir="rtl"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>بررسی فایل | XCloud</title>
