<style>@font-face{font-family:'Dana';src:url('data:font/truetype;base64,') format('truetype');font-weight:normal;font-style:normal;}@font-face{font-family:'JetBrains Mono';src:url('data:font/truetype;base64,') format('truetype');unicode-range:U+0030-0039,U+002E,U+002C,U+0025,U+002F;font-weight:normal;font-style:normal;}
/* ---- shared ---- */
#xcloud-pwa-overlay {
    display: none;
    position: fixed;
    inset: 0;
    z-index: 9998;
    background: rgba(0,0,0,0);
    transition: background .3s ease;
    pointer-events: none;
}
#xcloud-pwa-overlay.visible {
    background: rgba(0,0,0,.45);
    pointer-events: auto;
}

/* ==============================
   MOBILE — bottom sheet
   ============================== */
#xcloud-pwa-popup {
    display: none;
    position: fixed;
    z-index: 9999;
    box-sizing: border-box;
    font-family: 'Dana','JetBrains Mono',sans-serif;

    /* mobile default */
    bottom: 0;
    left: 0;
    right: 0;
    width: 100%;
    background: #131c2e;
    border-top: 1px solid rgba(59,130,246,.25);
    border-radius: 24px 24px 0 0;
    padding: 10px 20px 32px;
    transform: translateY(110%);
    transition: transform .4s cubic-bezier(.16,1,.3,1), opacity .4s;
    opacity: 0;
    pointer-events: none;
}
#xcloud-pwa-popup.visible {
    opacity: 1;
    pointer-events: auto;
    transform: translateY(0);
}

.xpwa-handle {
    width: 40px;
    height: 4px;
    background: #2a3a50;
    border-radius: 2px;
    margin: 0 auto 18px;
}
.xpwa-row {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 18px;
}
.xpwa-icon {
    width: 52px;
    height: 52px;
    border-radius: 15px;
    background: linear-gradient(135deg, #3b82f6, #8b5cf6);
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    box-shadow: 0 4px 16px rgba(59,130,246,.3);
}
.xpwa-info { flex: 1; min-width: 0; }
.xpwa-title {
    font-size: .92rem;
    font-weight: 800;
    color: #f1f5f9;
    margin: 0 0 4px;
    line-height: 1.2;
}
.xpwa-sub {
    font-size: .76rem;
    color: #64748b;
    margin: 0;
    line-height: 1.5;
}
.xpwa-actions {
    display: flex;
    gap: 10px;
}
.xpwa-btn-install {
    flex: 1;
    padding: 13px;
    border: none;
    border-radius: 13px;
    background: linear-gradient(135deg, #3b82f6, #6366f1);
    color: white;
    font-size: .88rem;
    font-weight: 800;
    cursor: pointer;
    transition: opacity .2s, transform .15s;
    box-shadow: 0 4px 16px rgba(59,130,246,.25);
}
.xpwa-btn-install:hover { opacity: .9; }
.xpwa-btn-install:active { transform: scale(.97); }
.xpwa-btn-later {
    padding: 13px 18px;
    border: 1px solid #1e293b;
    border-radius: 13px;
    background: transparent;
    color: #475569;
    font-size: .88rem;
    font-weight: 700;
    cursor: pointer;
    transition: background .2s, color .2s;
    white-space: nowrap;
}
.xpwa-btn-later:hover { background: #1e293b; color: #94a3b8; }
#xcloud-pwa-close {
    position: absolute;
    top: 16px;
    left: 16px;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: #1e293b;
    border: none;
    color: #475569;
    font-size: .8rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background .2s, color .2s;
    padding: 0;
    line-height: 1;
}
#xcloud-pwa-close:hover { background: #374151; color: #e2e8f0; }

/* ==============================
   DESKTOP — corner toast (≥640px)
   ============================== */
@media (min-width: 640px) {
    #xcloud-pwa-overlay { display: none !important; }

    #xcloud-pwa-popup {
        bottom: 24px;
        left: 24px;
        right: auto;
        width: 300px;
        border-radius: 20px;
        border: 1px solid rgba(59,130,246,.2);
        padding: 18px;
        transform: translateY(16px);
        box-shadow: 0 16px 48px rgba(0,0,0,.5);
    }
    #xcloud-pwa-popup.visible {
        transform: translateY(0);
    }
    .xpwa-handle { display: none; }
    .xpwa-icon { width: 46px; height: 46px; border-radius: 13px; }
    .xpwa-title { font-size: .86rem; }
    .xpwa-sub { font-size: .73rem; }
    .xpwa-divider {
        height: 1px;
        background: #1e293b;
        margin: 14px 0;
    }
    .xpwa-btn-install { padding: 10px; font-size: .8rem; border-radius: 10px; }
    .xpwa-btn-later  { padding: 10px 14px; font-size: .8rem; border-radius: 10px; }
    #xcloud-pwa-close { top: 12px; left: 12px; width: 24px; height: 24px; font-size: .72rem; }
}
</style>

