    <div class="xpwa-row">
        <div class="xpwa-icon">
            <img src="/icons/web-app-manifest-512x512.png" alt="XCloud" style="width:38px;height:38px;border-radius:10px;object-fit:contain;">
        </div>
        <div class="xpwa-info">
            <p class="xpwa-title">نصب XCloud</p>
            <p class="xpwa-sub">اپ را به صفحه اصلی اضافه کنید<br>و بدون مرورگر استفاده کنید</p>
        </div>
    </div>
    <div class="xpwa-divider"></div>
    <div class="xpwa-actions">
        <button class="xpwa-btn-install" id="xcloud-pwa-install">نصب اپ</button>
        <button class="xpwa-btn-later"   id="xcloud-pwa-later">بعداً</button>
    </div>
</div>

<script>
(function () {
    var REMIND_AFTER_DAYS = 1;
    var SHOW_DELAY_MS     = 2500;
    var STORAGE_KEY       = 'xcloud_pwa_dismissed';
    var INSTALLED_KEY     = 'xcloud_pwa_installed';

    var popup      = document.getElementById('xcloud-pwa-popup');
    var overlay    = document.getElementById('xcloud-pwa-overlay');
    var btnClose   = document.getElementById('xcloud-pwa-close');
    var btnInstall = document.getElementById('xcloud-pwa-install');
    var btnLater   = document.getElementById('xcloud-pwa-later');
    var deferredPrompt = null;

    // اگه قبلاً نصب شده یا standalone هست، کاری نکن
    var isStandalone = window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true;
    if (isStandalone) return;

    // شناسایی iOS
    var isIOS = /iphone|ipad|ipod/i.test(navigator.userAgent) && !window.MSStream;

    function shouldShow() {
        if (localStorage.getItem(INSTALLED_KEY)) return false;
        var raw = localStorage.getItem(STORAGE_KEY);
        if (!raw) return true;
        try {
            var days = (Date.now() - JSON.parse(raw).ts) / 86400000;
            return days >= REMIND_AFTER_DAYS;
        } catch (e) { return true; }
    }

    function isMobile() { return window.innerWidth < 640; }

    function showPopup() {
        if (!shouldShow()) return;
        popup.style.display = 'block';
        if (isMobile()) overlay.style.display = 'block';
        requestAnimationFrame(function () {
            requestAnimationFrame(function () {
                popup.classList.add('visible');
                if (isMobile()) overlay.classList.add('visible');
            });
        });
    }

    function hidePopup(permanent) {
        popup.classList.remove('visible');
        overlay.classList.remove('visible');
        setTimeout(function () {
            popup.style.display = 'none';
            overlay.style.display = 'none';
        }, 420);
        if (permanent) {
            localStorage.setItem(INSTALLED_KEY, '1');
        } else {
            localStorage.setItem(STORAGE_KEY, JSON.stringify({ ts: Date.now() }));
        }
    }

    btnClose.addEventListener('click', function () { hidePopup(false); });
    btnLater.addEventListener('click', function () { hidePopup(false); });
    overlay.addEventListener('click', function (e) { if (e.target === overlay) hidePopup(false); });

    // ── iOS Safari: beforeinstallprompt پشتیبانی نمیشه ──────────
    if (isIOS) {
        var titleEl = popup.querySelector('.xpwa-title');
        var subEl   = popup.querySelector('.xpwa-sub');
        if (titleEl) titleEl.textContent = 'نصب روی iPhone / iPad';
        if (subEl)   subEl.innerHTML = 'دکمه <strong>اشتراک‌گذاری</strong> 🔗 را بزنید<br>سپس <strong>«Add to Home Screen»</strong> را انتخاب کنید';
        if (btnInstall) {
            btnInstall.textContent = 'متوجه شدم ✓';
            btnInstall.addEventListener('click', function () { hidePopup(true); });
        }
        setTimeout(showPopup, SHOW_DELAY_MS);
        return;
    }

    // ── Android / Chrome / Desktop ────────────────────────────────
    btnInstall.addEventListener('click', function () {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        deferredPrompt.userChoice.then(function (r) {
            if (r.outcome === 'accepted') hidePopup(true);
            deferredPrompt = null;
        });
    });

    window.addEventListener('beforeinstallprompt', function (e) {
        e.preventDefault();
        deferredPrompt = e;
        var headerBtn = document.getElementById('pwa-install-btn');
        if (headerBtn) headerBtn.style.display = 'inline-flex';
        setTimeout(showPopup, SHOW_DELAY_MS);
    });

    window.addEventListener('appinstalled', function () {
        hidePopup(true);
        var headerBtn = document.getElementById('pwa-install-btn');
        if (headerBtn) headerBtn.style.display = 'none';
    });

    window.installPWA = function () {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        deferredPrompt.userChoice.then(function (r) {
            if (r.outcome === 'accepted') hidePopup(true);
            deferredPrompt = null;
        });
    };
})();
</script>
    </body></html><?php exit;
}

if($action=='add_user'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $nu=trim($_POST['new_username']??'');$np=$_POST['new_password']??'';
    $nr=in_array($_POST['new_role']??'',['admin','user'])?$_POST['new_role']:'user';
    $cd=isset($_POST['can_download'])?1:0;$ccp=isset($_POST['can_change_password'])?1:0;$cdel=isset($_POST['can_delete'])?1:0;$csh=isset($_POST['can_share'])?1:0;
    if($nr==='admin'){$cd=1;$ccp=1;$cdel=1;$csh=1;}
    if(!empty($nu)&&!empty($np)&&strlen($nu)>=3&&strlen($np)>=4){
        $ex=$pdo->prepare("SELECT id FROM users WHERE username=?");$ex->execute([$nu]);
        if(!$ex->fetch()){$h=password_hash($np,PASSWORD_DEFAULT);
            $s=$pdo->prepare("INSERT INTO users (username,password,role,can_download,can_change_password,can_delete,can_share) VALUES(?,?,?,?,?,?,?)");
            $s->execute([$nu,$h,$nr,$cd,$ccp,$cdel,$csh]);getUserUploadPath($nu);logActivity($pdo,$_SESSION['user'],'add_user',$nu,"نقش: $nr");
            header("Location: ?action=users&msg=user_added");exit;}
        header("Location: ?action=users&msg=user_exists");exit;
    }
    header("Location: ?action=users&msg=invalid_input");exit;
}

if($action=='delete_user'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $uid=(int)($_POST['user_id']??0);
    if($uid>0){$c=$pdo->prepare("SELECT username FROM users WHERE id=?");$c->execute([$uid]);$t=$c->fetch();
        if($t&&$t['username']!==$_SESSION['user']){$pdo->prepare("DELETE FROM users WHERE id=?")->execute([$uid]);
            logActivity($pdo,$_SESSION['user'],'delete_user',$t['username']);header("Location: ?action=users&msg=user_deleted");exit;}}
    header("Location: ?action=users&msg=delete_error");exit;
}

if($action=='update_permissions'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $uid=(int)($_POST['user_id']??0);$field=$_POST['field']??'';$val=(int)($_POST['value']??0);
    $af=['can_download','can_change_password','can_delete','can_share'];
    if($uid>0&&in_array($field,$af)&&in_array($val,[0,1])){
        $c=$pdo->prepare("SELECT role,username FROM users WHERE id=?");$c->execute([$uid]);$t=$c->fetch();
        if($t&&$t['role']!=='admin'){$pdo->prepare("UPDATE users SET $field=? WHERE id=?")->execute([$val,$uid]);
            logActivity($pdo,$_SESSION['user'],'update_permissions',$t['username'],"$field=$val");
            header("Location: ?action=users&msg=perms_updated");exit;}}
    header("Location: ?action=users&msg=perms_error");exit;
}

if($action=='change_password'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $pc=$pdo->prepare("SELECT can_change_password,role FROM users WHERE username=?");$pc->execute([$_SESSION['user']]);$pr=$pc->fetch();
    if(!$pr||($pr['role']!=='admin'&&!$pr['can_change_password'])){header("Location: ?action=dashboard&msg=no_permission");exit;}
    $cp=$_POST['current_password']??'';$np=$_POST['new_password']??'';
    $s=$pdo->prepare("SELECT password FROM users WHERE username=?");$s->execute([$_SESSION['user']]);$r=$s->fetch();
    if($r&&password_verify($cp,$r['password'])&&strlen($np)>=4){
        $pdo->prepare("UPDATE users SET password=? WHERE username=?")->execute([password_hash($np,PASSWORD_DEFAULT),$_SESSION['user']]);
        logActivity($pdo,$_SESSION['user'],'change_password');header("Location: ?action=dashboard&msg=password_changed");exit;}
    header("Location: ?action=dashboard&msg=password_error");exit;
}

if($action=='admin_change_password'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $uid=(int)($_POST['user_id']??0);$np=$_POST['new_password']??'';
    if($uid>0&&strlen($np)>=4){$c=$pdo->prepare("SELECT username FROM users WHERE id=?");$c->execute([$uid]);$t=$c->fetch();
        if($t){$pdo->prepare("UPDATE users SET password=? WHERE id=?")->execute([password_hash($np,PASSWORD_DEFAULT),$uid]);
            logActivity($pdo,$_SESSION['user'],'change_password',$t['username'],'ادمین');header("Location: ?action=users&msg=password_changed");exit;}}
    header("Location: ?action=users&msg=password_error");exit;
}

// ---- Trash Actions ----
if($action=='trash_restore'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $tid=(int)($_POST['trash_id']??0);
    $s=$pdo->prepare("SELECT * FROM trash_items WHERE id=?");$s->execute([$tid]);$item=$s->fetch();
    if($item){
        $tp=$trash_base.$item['trash_filename'];
        $rp=getUserUploadPath($item['original_owner']).$item['original_filename'];
        if(file_exists($rp)){$ext=pathinfo($item['original_filename'],PATHINFO_EXTENSION);$nm=pathinfo($item['original_filename'],PATHINFO_FILENAME);$rp=getUserUploadPath($item['original_owner']).$nm.'_restored_'.time().($ext?".$ext":'');}
        if(file_exists($tp)&&rename($tp,$rp)){
            $pdo->prepare("DELETE FROM trash_items WHERE id=?")->execute([$tid]);
            logActivity($pdo,$_SESSION['user'],'trash_restore',$item['original_filename'],"به: ".$item['original_owner']);
            header("Location: ?action=trash&msg=restored");exit;}}
    header("Location: ?action=trash&msg=restore_error");exit;
}

if($action=='trash_delete_permanent'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $tid=(int)($_POST['trash_id']??0);
    $s=$pdo->prepare("SELECT * FROM trash_items WHERE id=?");$s->execute([$tid]);$item=$s->fetch();
    if($item){$tp=$trash_base.$item['trash_filename'];if(file_exists($tp))@unlink($tp);
        $pdo->prepare("DELETE FROM trash_items WHERE id=?")->execute([$tid]);
        logActivity($pdo,$_SESSION['user'],'trash_delete',$item['original_filename'],'حذف دائم');
        header("Location: ?action=trash&msg=perm_deleted");exit;}
    header("Location: ?action=trash&msg=not_found");exit;
}

if($action=='trash_empty'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $items=$pdo->query("SELECT * FROM trash_items")->fetchAll();
    foreach($items as $it){$tp=$trash_base.$it['trash_filename'];if(file_exists($tp))@unlink($tp);}
    $pdo->exec("DELETE FROM trash_items");
