    <script>
    function b64d(s){s=s.replace(/-/g,'+').replace(/_/g,'/');while(s.length%4)s+='=';const b=atob(s),a=new Uint8Array(b.length);for(let i=0;i<b.length;i++)a[i]=b.charCodeAt(i);return a.buffer;}
    function b64e(buf){const a=buf instanceof ArrayBuffer?new Uint8Array(buf):new Uint8Array(buf);return btoa(String.fromCharCode(...a)).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');}
    async function pkLogin(){
        const btn=document.getElementById('pkBtn'),st=document.getElementById('pkSt');
        if(!window.PublicKeyCredential){st.className='e';st.textContent='مرورگر از Passkey پشتیبانی نمی‌کند';return;}
        btn.disabled=true;btn.style.opacity='.6';st.className='';st.textContent='در حال آماده‌سازی...';
        try{
            const opts=await (await fetch('?action=passkey_auth_challenge')).json();
            opts.challenge=b64d(opts.challenge);
            if(opts.allowCredentials)opts.allowCredentials=opts.allowCredentials.map(c=>({...c,id:b64d(c.id),transports:['internal']}));
            // Force device-only — block Google Password Manager
            opts.hints=['client-device'];
            opts.userVerification='required';
            st.textContent='لطفاً بیومتریک یا PIN خود را تأیید کنید...';
            const cred=await navigator.credentials.get({publicKey:opts});
            const body={id:cred.id,clientDataJSON:b64e(cred.response.clientDataJSON),
                authenticatorData:b64e(cred.response.authenticatorData),signature:b64e(cred.response.signature)};
            st.textContent='در حال تأیید...';
            const res=await(await fetch('?action=passkey_auth_verify',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)})).json();
            if(res.ok){st.className='ok';st.textContent='✓ ورود موفق...';location.href=res.redirect;}
            else throw new Error(res.error||'خطا');
        }catch(e){
            btn.disabled=false;btn.style.opacity='';
            st.className='e';
            st.textContent=e.name==='NotAllowedError'?'عملیات لغو شد':'خطا: '+e.message;
        }
    }
    </script>
    </body></html><?php
}

