    .txt-content{font-family:'Courier New',monospace;font-size:.72rem;color:#94a3b8;padding:10px 12px;white-space:pre-wrap;word-break:break-all;line-height:1.5;max-height:90px;overflow:hidden;display:block}
    .txt-copy-btn{width:100%;padding:6px;background:rgba(59,130,246,.08);border:none;border-top:1px solid var(--border);color:var(--primary);font-size:.72rem;font-weight:700;cursor:pointer;transition:background .2s}
    .txt-copy-btn:hover{background:rgba(59,130,246,.15)}

    /* FILE ACTIONS */
    .file-actions{display:flex;gap:6px;margin-top:10px;flex-wrap:wrap}
