    .modal-box input:focus{border-color:var(--primary)}
    .modal-actions{display:flex;gap:8px}
    .modal-actions button{flex:1;padding:11px;border-radius:var(--r-sm);font-weight:700;cursor:pointer;border:none;font-size:.84rem}
