46,.1);color:#60a5fa}.log-action.danger{background:rgba(239,68,68,.1);color:#f87171}.log-action.warning{background:rgba(245,158,11,.1);color:#fbbf24}.log-action.success{background:rgba(34,197,94,.1);color:#4ade80}.log-target{font-size:.75rem;color:#94a3b8}.log-details{font-size:.7rem;color:#64748b}.log-ip{font-size:.65rem;color:#475569;font-family:monospace}.pagination{display:flex;justify-content:center;gap:6px;margin-top:18px}.page-btn{padding:7px 12px;border-radius:9px;text-decoration:none;font-size:.8rem;font-weight:600;border:1px solid #1e293b;background:#111827;color:#e2e8f0;transition:all .2s}.page-btn.active{background:rgba(59,130,246,.15);border-color:#3b82f6;color:#3b82f6}.page-btn.disabled{opacity:.3;pointer-events:none}.total-badge{font-size:.74rem;color:#64748b;margin-bottom:10px}</style>
